('adrienallard-fileconverter', 'File Converter', 'File Converter is a very simple tool which allows you to convert and compress one or several file(s) using the context menu in windows explorer.', 'Utilities', 'adrienallard-fileconverter-icon', '', 0, 'https://file-converter.org'),
('advice-myadvice-auftragsverwaltung', 'myADVICE.Auftragsverwaltung', 'myADVICE.Auftragsverwaltung ist ein Kunden- und Rechnungsverwaltung (Offerte, Auftragsbestätigung, Rechnung, Serienrechnung) Applikation für kleine Unternehmen.', 'Utilities', 'advice-myadvice-auftragsverwaltung-icon', '', 0, ''),
('aegisub-aegisub', 'Aegisub', 'Aegisub is a free, cross-platform open source tool for creating and modifying subtitles. Aegisub makes it quick and easy to time subtitles to audio, and features many powerful tools for styling them, including a built-in real-time video preview.', 'Development', 'aegisub-aegisub-icon', '', 0, 'https://aeg-dev.github.io/AegiSite/'),
('aegisub-aegisub-dev', 'Aegisub (Dev)', 'Aegisub is a free, cross-platform open source tool for creating and modifying subtitles. Aegisub makes it quick and easy to time subtitles to audio, and features many powerful tools for styling them, including a built-in real-time video preview.', 'Development', 'aegisub-aegisub-dev-icon', '', 0, 'http://plorkyeran.com/aegisub/'),
