('bisq-bisq', 'Bisq', 'Buy and sell bitcoin for fiat (or other cryptocurrencies) privately and securely using Bisq''s peer-to-peer network and open-source desktop software. No registration required.', 'Utilities', 'bisq-bisq-icon', '', 0, 'https://bisq.network'),
('bitguardian-bitdriverupdater', 'Bit Driver Updater', 'Bit Driver Updater helps computers to detect defective drivers, install driver updates when needed, and fix other driver-related issues.', 'Utilities', 'bitguardian-bitdriverupdater-icon', '', 0, 'https://www.bitdriverupdater.com/'),
('bitguardian-bitgamebooster', 'Bit Game Booster', 'Bit Game Booster is specifically designed to uplift your gaming experience by helping you get the most out of your PC.', 'Games', 'bitguardian-bitgamebooster-icon', '', 0, 'https://www.bitgamebooster.com/'),
('bitrecover-aadhaarcardpasswordremover', 'Aadhaar Card Password Remover', 'Free Aadhaar Card Password Remover allows removing unlimited Aadhaar PDF files password with company watermark.', 'Office', 'bitrecover-aadhaarcardpasswordremover-icon', 'LibreOffice Writer / ONLYOFFICE', 50, 'https://www.bitrecover.com/aadhaar-card-password-remover/'),
('bitrecover-windowslivemailconverter', 'BitRecover Windows Live Mail Converter Wizard', 'This program gives the facility to migrate from WLM to multiple generic file extensions such as PST, MSG, EML, EMLX, TXT, MBOX, HTML, MHT, XPS, RTF, DOC, Windows Live Mail, CSV, Gmail, Yahoo, TIFF, BMP, GIF, JPEG, PNG, PDF, NSF, TGZ, OLM, etc. It gives freedom to transfer folders from Windows Live Mail to various cloud-based email services and servers, i.e., Gmail, Yahoo, Outlook.com, Office 365, Exchange Server, Hosted Exchange Server, G Suite, IBM Verse, Amazon WorkMail, IMAP Server, etc. The tool has an inbuilt feature to automatically load WLM folders in the software panel from the default storage location. It has another option to load emails manually from any other storage location. Moreover, after the start, the tool is will automatically load overall Windows Live Mail databases in the software panel, including all email folders in Windows Explorer style.', 'Development', 'bitrecover-windowslivemailconverter-icon', '', 0, 'https://www.bitrecover.com/windows-live-mail-converter'),
('bitsum-coreprio', 'Coreprio', 'Coreprio is a free, open source CPU optimization utility for the AMD 2990wx and 2970wx processors on Windows. It offers two features: (1) our implementation of AMD’s Dynamic Local Mode and (2) our new ‘NUMA Dissociater’.', 'Utilities', 'bitsum-coreprio-icon', '', 0, ''),
('bitsum-parkcontrol', 'ParkControl', 'ParkControl is free software to display and tweak CPU core parking settings in real-time. It also has an assortment of complimentary power automation features.', 'Utilities', 'bitsum-parkcontrol-icon', '', 0, ''),
('bitsum-processlasso', 'Process Lasso', 'Process Lasso is a tool designed to manage and edit how your processes and services run. It offers a robust list of capabilities including default process priorities and affinities, termination of disallowed processes, instance count limits, a system responsiveness graph, logging of processes, keep select processes running (auto-restart), and much more.', 'Design', 'bitsum-processlasso-icon', '', 0, 'https://bitsum.com'),
('bitsum-processlasso-beta', 'Process Lasso Beta', 'Process Lasso is a tool designed to manage and edit how your processes and services run. It offers a robust list of capabilities including default process priorities and affinities, termination of disallowed processes, instance count limits, a system responsiveness graph, logging of processes, keep select processes running (auto-restart), and much more.', 'Design', 'bitsum-processlasso-beta-icon', '', 0, 'https://bitsum.com'),
('bitcoincoreproject-bitcoincore', 'Bitcoin Core', 'Bitcoin Core is an open source project which maintains and releases Bitcoin client software called Bitcoin Core.', 'Utilities', 'bitcoincoreproject-bitcoincore-icon', '', 0, 'https://bitcoincore.org/en/download/'),
('bitdefender-bitdefender', 'BitDefender Agent', 'Bitdefender Antivirus Free Edition is a free antivirus software especially designed to protect your Windows PC.', 'Design', 'bitdefender-bitdefender-icon', '', 0, 'https://www.bitdefender.com/solutions/free.html'),
('bitnami-drupal', 'Drupal packaged by Bitnami', 'Drupal is one of the most versatile open source content management systems in the world. It is pre-configured with the Ctools and Views modules, Drush and Let’s Encrypt auto-configuration support.', 'Utilities', 'bitnami-drupal-icon', '', 0, 'https://bitnami.com/stack/drupal'),
('bitnami-joomla', 'Bitnami Joomla! Stack', 'Joomla! is an award winning open source CMS platform for building websites and applications. It includes page caching, page compression and Let’s Encrypt auto-configuration support.', 'Utilities', 'bitnami-joomla-icon', '', 0, 'https://bitnami.com/stack/joomla'),
