('brave-brave-beta', 'Brave Beta', 'Brave Beta is an early preview for new versions of Brave. This build showcases the newest advances that we’re bringing to your browser and it’s ready for your daily use. Brave Beta automatically sends us crash reports when things go wrong.', 'Utilities', 'brave-brave-beta-icon', '', 50, 'https://brave.com/download-beta/'),
('brave-brave-dev', 'Brave Dev', 'Secure, Fast & Private Web Browser with Adblocker', 'Utilities', 'brave-brave-dev-icon', '', 50, ''),
('brave-brave-nightly', 'Brave Nightly', 'Nightly is our testing and development version of Brave. The releases are updated every night and may contain bugs that can result in data loss. Nightly automatically sends us crash reports when things go wrong.', 'Development', 'brave-brave-nightly-icon', '', 50, 'https://brave.com/download-nightly/'),
('brianapps-sizer', 'Sizer', 'Sizer is a freeware utility that allows you to resize any window to an exact, predefined size.', 'Utilities', 'brianapps-sizer-icon', '', 0, 'http://www.brianapps.net/sizer/'),
('brianapps-sizer-dev', 'Sizer (Dev)', 'Sizer is a freeware utility that allows you to resize any window to an exact, predefined size.', 'Utilities', 'brianapps-sizer-dev-icon', '', 0, 'http://www.brianapps.net/sizer4/'),
('bricklink-studio', 'Studio', 'Build, render, and create LEGO instructions. Do it all in Studio 2.0. Intuitive and easy building.', 'Design', 'bricklink-studio-icon', '', 0, 'https://www.bricklink.com/v2/build/studio.page'),
('brio-foldersize', 'Folder Size', 'Folder Size for Windows opens pop-up windows that track open Explorer windows. The new window shows not only the size of files, but also the size of folders. It keeps track of which folders you view, and scans them in the background so you can see complete size of all files within the folder. It''s very useful for cleaning up your disk. Once you get used to having that information available, a directory listing simply looks incomplete without it!', 'Utilities', 'brio-foldersize-icon', '', 0, 'http://foldersize.sourceforge.net/'),
('brunobanelli-pci-z', 'PCI-Z', 'PCI-Z is a lightweight system utility designed to provide information about unknown PCI, PCI-E and PCI-X devices and helps you find appropriate device drivers.', 'Development', 'brunobanelli-pci-z-icon', '', 0, 'https://www.pci-z.com/'),
('brunonova-collision', 'Collision', 'In this game you control a green ball. Using your mouse or keyboard, you have to avoid hitting the ever increasing number of red balls that are moving around in the game window. The moment you touch one of them, the game is over.

The game has three difficulty levels and two modes:
- Time: you have to dodge the red balls for as long as possible. Every few seconds a new red ball appears. The longer you last, the higher the score will be.
- Coins: you have to catch as many coins as you can. Every few coins a new red ball appears. The more coins you gather, the higher the score will be.

During the game different bonuses can also appear. These can provide either a positive or a negative effect.
', 'Games', 'brunonova-collision-icon', '', 0, 'https://github.com/brunonova/collision2'),
('brunonova-drmips', 'DrMIPS', 'DrMIPS is a graphical simulator of the MIPS processor to support computer  architecture teaching and learning. It is intuitive, versatile and configurable.
The simulator is available not only for personal computers but also for Android devices, especially tablets.
DrMIPS was created under the Master’s dissertation entitled Tool to Support Computer Architecture Teaching and Learning at the Faculty of Engineering of the University of Porto, in Portugal.
Requires Java 8 or later.', 'Design', 'brunonova-drmips-icon', '', 0, 'https://brunonova.github.io/drmips/'),
('brutalchess-brutalchess', 'Brutal Chess', 'Brutal Chess features full 3D graphics, an advanced particle engine, and several different levels of intelligent AI, inspired by the once popular »Battle Chess« released by Interplay circa 1988.', 'Games', 'brutalchess-brutalchess-icon', '', 0, 'https://sourceforge.net/projects/brutalchess/'),
('microsoft-notepad', 'Microsoft Notepad', 'Plain text editor pre-installed with Microsoft Windows, used for simple text editing.', 'Windows Integrated', 'microsoft-notepad-icon', 'Kate / Gedit / Mousepad', 80, 'https://apps.microsoft.com/detail/9msml7506f30'),
('microsoft-paint', 'Microsoft Paint', 'Simple raster graphics editor pre-installed in all versions of Microsoft Windows.', 'Windows Integrated', 'microsoft-paint-icon', 'Pinta / KolourPaint / Drawing', 80, 'https://apps.microsoft.com/detail/9pcfs5b6t72h'),
('microsoft-snippingtool', 'Snipping Tool', 'Screenshot utility included in Microsoft Windows to capture screen snippets.', 'Windows Integrated', 'microsoft-snippingtool-icon', 'Flameshot / Spectacle / GNOME Screenshot', 60, 'https://apps.microsoft.com/detail/9mz95kl8mr0l'),
('microsoft-taskmanager', 'Windows Task Manager', 'Built-in system monitor, task manager, and startup manager in Microsoft Windows.', 'Windows Integrated', 'microsoft-taskmanager-icon', 'GNOME System Monitor / KDE System Monitor / htop', 70, 'https://learn.microsoft.com/en-us/sysinternals/downloads/process-explorer'),
('microsoft-calculator', 'Windows Calculator', 'The standard calculator application pre-installed with Microsoft Windows.', 'Windows Integrated', 'microsoft-calculator-icon', 'GNOME Calculator / KCalc', 50, 'https://apps.microsoft.com/detail/9wzdncrfhwd2'),
('microsoft-wordpad', 'WordPad', 'Basic word processor included in Microsoft Windows since Windows 95 (now deprecated).', 'Windows Integrated', 'microsoft-wordpad-icon', 'LibreOffice Writer / AbiWord', 40, 'https://support.microsoft.com/en-us/windows/wordpad-is-no-longer-being-updated-592f6c91-d8ad-4fb3-bb55-a08fa00ef60b'),
('microsoft-visio', 'Microsoft Visio', 'Vector graphics and diagramming application for creating flowcharts and diagrams.', 'Design', 'microsoft-visio-icon', 'Draw.io / Inkscape', 60, 'https://www.microsoft.com/en-us/microsoft-365/visio/flowchart-software'),
('microsoft-publisher', 'Microsoft Publisher', 'Desktop publishing application from Microsoft, focusing on page layout and design.', 'Design', 'microsoft-publisher-icon', 'Scribus', 50, 'https://www.microsoft.com/en-us/microsoft-365/publisher'),
('microsoft-access', 'Microsoft Access', 'Database management system from Microsoft that combines relational database engine with GUI tools.', 'Development', 'microsoft-access-icon', 'LibreOffice Base / DBeaver', 50, 'https://www.microsoft.com/en-us/microsoft-365/access');

INSERT INTO reports (id, app_id, rating, runner, details, date) VALUES
('1', 'adobe-photoshop', 'Silver', 'Bottles (Soda)', 'Works using the Soda runner in Bottles. The installation fails on the first try, so you must use the offline installer. Decent performance.', '2026-06-14'),
('2', 'microsoft-office', 'Bronze', 'Wine', 'Word and Excel work okay, but advanced macros, plugins, and cloud licensing crash the application.', '2026-06-13'),
('3', 'autodesk-autocad', 'Garbage', 'CrossOver', 'Impossible to install. Fails at the licensing service and does not render the viewport canvas.', '2026-06-10'),
('4', 'imageline-flstudio', 'Platinum', 'Lutris', 'Using the latest Lutris-GE version. Audio works perfectly with Pipewire-ALSA. Loads all VSTs with no issues.', '2026-06-12'),
('5', 'epicgames-epicgameslauncher', 'Platinum', 'Lutris', 'Runs well using Lutris or Bottles. However, using the native Heroic Games Launcher is highly recommended as a superior alternative.', '2026-06-14'),
('6', 'discord-discord', 'Native', 'Native', 'Works perfectly native. Install the Flatpak version for sandbox security.', '2026-06-14'),
('7', 'spotify-spotify', 'Native', 'Native', 'Official Linux client is available and works perfectly. Zero lag.', '2026-06-14'),
('8', 'rarlab-winrar', 'Gold', 'Wine', 'Runs flawlessly under Wine, but PeaZip is a native Linux tool and works much better.', '2026-06-14'),
('9', 'bittorrent-utorrent', 'Silver', 'Wine', 'Runs in Wine but has ads. Recommend switching to qBittorrent which is native and ad-free.', '2026-06-14'),
('10', 'akeo-rufus', 'Garbage', 'Wine', 'Low level USB disk writer cannot access hardware through Wine translation. Use Ventoy natively instead.', '2026-06-14'),
('11', 'google-chrome', 'Native', 'Native', 'Google Chrome has a native version for Linux and works perfectly.', '2026-06-14'),
('12', 'valve-steam', 'Native', 'Native', 'Steam runs natively on Linux. Highly recommended to use the official package or Flatpak.', '2026-06-14'),
('13', 'adobe-premiere-pro', 'Garbage', 'Wine', 'Does not install. Creative Cloud desktop app crashes and licensing fails. Use DaVinci Resolve or Kdenlive instead.', '2026-06-14'),
('14', 'adobe-illustrator', 'Bronze', 'Wine', 'Older versions (CS6) run okay, but modern CC versions crash during startup. Inkscape is a great native alternative.', '2026-06-14'),
('15', 'igor-7zip', 'Gold', 'Wine', 'Runs perfectly, but PeaZip is native and integrates with the Linux desktop environment much better.', '2026-06-14'),
('16', 'whatsapp-desktop', 'Native', 'Native', 'Use WhatsApp Web in browser or native open-source clients like ZapZap.', '2026-06-14'),
('17', 'videolan-vlc', 'Native', 'Native', 'VLC is native to Linux and works perfectly.', '2026-06-14'),
('18', 'notepad-plusplus', 'Platinum', 'Wine', 'Runs flawlessly under Wine. However, native editors like VS Code or Notepadqq are recommended.', '2026-06-14'),
('19', 'teamviewer-teamviewer', 'Native', 'Native', 'Official native TeamViewer package is available for Linux and works great.', '2026-06-14'),
('20', 'microsoft-skype', 'Native', 'Native', 'Official native client works perfectly.', '2026-06-14'),
('21', 'zoom-zoom', 'Native', 'Native', 'Zoom offers a native Linux client which is fully functional.', '2026-06-14'),
('r-notepad', 'microsoft-notepad', 'Platinum', 'Wine', 'Runs flawlessly under Wine, but native editors like Kate or Gedit are pre-installed on Linux.', '2026-06-14'),
('r-paint', 'microsoft-paint', 'Gold', 'Wine', 'Can be run using Wine, but native alternatives like Pinta or Drawing are much faster and integrate better.', '2026-06-14'),
('r-snippingtool', 'microsoft-snippingtool', 'Garbage', 'Wine', 'Low-level Windows desktop capture APIs do not work properly through Wine. Use native screenshot tools like Spectacle or Flameshot.', '2026-06-14'),
('r-taskmanager', 'microsoft-taskmanager', 'Garbage', 'Wine', 'Cannot monitor Linux system resources through Wine translation. Use GNOME/KDE System Monitor or htop natively.', '2026-06-14'),
('r-calculator', 'microsoft-calculator', 'Platinum', 'Wine', 'Runs fine in Wine, but native calculators are instantly available on any Linux desktop.', '2026-06-14'),
('r-wordpad', 'microsoft-wordpad', 'Gold', 'Wine', 'Runs well in Wine, but LibreOffice Writer is a vastly superior native alternative.', '2026-06-14'),
('r-visio', 'microsoft-visio', 'Silver', 'Wine', 'Can run under Wine with some font configuration tweaks. Draw.io is a great native web/desktop alternative.', '2026-06-14'),
('r-publisher', 'microsoft-publisher', 'Silver', 'Wine', 'Runs okay with Wine, but Scribus is the recommended native Linux alternative.', '2026-06-14'),
('r-access', 'microsoft-access', 'Bronze', 'Wine', 'Database engine has issues with lock files over network shares under Wine. Use DBeaver or LibreOffice Base natively.', '2026-06-14');
